            Console.WriteLine("Healthcare Record Service stopped");
        }
    }

    private WSHttpBinding CreateSecureBinding()
    {
        WSHttpBinding binding = new WSHttpBinding(SecurityMode.Message);

        binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        binding.Security.Message.NegotiateServiceCredential = true;
        binding.Security.Message.EstablishSecurityContext = true;

        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        binding.MaxReceivedMessageSize = 2147483647;
        binding.MaxBufferPoolSize = 2147483647;
        binding.ReaderQuotas.MaxDepth = 32;
        binding.ReaderQuotas.MaxStringContentLength = 2147483647;
        binding.ReaderQuotas.MaxArrayLength = 2147483647;
        binding.ReaderQuotas.MaxBytesPerRead = 2147483647;
        binding.ReaderQuotas.MaxNameTableCharCount = 2147483647;

        binding.SendTimeout = TimeSpan.FromMinutes(10);
        binding.ReceiveTimeout = TimeSpan.FromMinutes(10);

        return binding;
    }

    private X509Certificate2 GetCertificate(StoreName storeName, StoreLocation storeLocation, string thumbprint)
    {
        X509Store store = new X509Store(storeName, storeLocation);
        try
        {
            store.Open(OpenFlags.ReadOnly);
            X509Certificate2Collection certificates = store.Certificates.Find(
                X509FindType.FindByThumbprint,
                thumbprint,
                false);

            if (certificates.Count == 0)
            {
                throw new Exception($"Certificate with thumbprint {thumbprint} not found");
            }

            return certificates[0];
        }
        finally
        {
            store.Close();
        }
    }
}

